export interface ConnectivitySnapshot {
    onLine: boolean;
    effectiveType?: string;
}

/**
 * `ok` means "reached the server", NOT "HTTP 2xx". A 502 still proves the
 * request reached something, which is the question this panel answers on
 * a flaky network. Network/DNS/abort errors produce `ok: false`.
 */
export type PingResult =
    | { ok: true; status: number; httpOk: boolean; latencyMs: number }
    | { ok: false; error: string; latencyMs: number };

export function snapshotConnectivity(): ConnectivitySnapshot {
    const conn = (navigator as unknown as { connection?: { effectiveType?: string } }).connection;
    return {
        onLine: navigator.onLine,
        ...(conn?.effectiveType ? { effectiveType: conn.effectiveType } : {}),
    };
}

export async function pingBackend(url: string, timeoutMs = 5000): Promise<PingResult> {
    const start = performance.now();
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);
    try {
        const response = await fetch(url, { method: 'GET', signal: controller.signal, cache: 'no-store' });
        const latencyMs = Math.round(performance.now() - start);
        return { ok: true, status: response.status, httpOk: response.ok, latencyMs };
    } catch (err) {
        const latencyMs = Math.round(performance.now() - start);
        const message = err instanceof Error ? (err.stack ?? err.message) : String(err);
        return { ok: false, error: message, latencyMs };
    } finally {
        clearTimeout(timer);
    }
}
