import { buildSectionPage } from '../../utils/section-page.utils.js';
import { API_URL } from '../../config.js';
import { getClientLogBuffer } from '../../services/debug/client-log-buffer.js';
import {
    getSwStatus, unregisterSw, updateSw, skipWaiting,
    type SwStatus,
} from '../../services/debug/sw-controls.js';
import {
    listCaches, listDatabases, clearAllCaches, deleteAllDatabases, nukeAndReload,
} from '../../services/debug/storage-controls.js';
import {
    snapshotConnectivity, pingBackend, type PingResult,
} from '../../services/debug/connectivity.js';
import '../log-viewer/log-viewer.component.js';
import type { LogViewer } from '../log-viewer/log-viewer.component.js';

export class DebugScreen extends HTMLElement {
    private initialized = false;
    private connectivityTimer: ReturnType<typeof setInterval> | null = null;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Debug', 'extra', '/debug');
        const intro = document.createElement('p');
        intro.textContent = 'In-app diagnostics. All errors are shown raw so they are instantly actionable on mobile.';
        page.content.appendChild(intro);

        page.content.appendChild(this.buildLogsPanel());
        page.content.appendChild(this.buildConnectivityPanel());
        page.content.appendChild(this.buildSwPanel());
        page.content.appendChild(this.buildStoragePanel());
    }

    disconnectedCallback(): void {
        if (this.connectivityTimer) {
            clearInterval(this.connectivityTimer);
            this.connectivityTimer = null;
        }
    }

    // ── Logs ────────────────────────────────────────────────────────────────

    private buildLogsPanel(): HTMLElement {
        const details = makePanel('Client Logs', true);

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';

        const refreshBtn = makeButton('Refresh', () => viewer.refresh(), 'logs-refresh');
        const downloadBtn = makeButton('Download .txt', () => this.handleDownloadLogs(), 'logs-download');
        const clearBtn = makeButton('Clear buffer', () => {
            getClientLogBuffer().clear();
            viewer.refresh();
        }, 'logs-clear');

        toolbar.append(refreshBtn, downloadBtn, clearBtn);
        details.appendChild(toolbar);

        const viewer = document.createElement('log-viewer') as LogViewer;
        viewer.availableLevels = ['debug', 'info', 'warn', 'error'];
        viewer.source = async (filters) => getClientLogBuffer().query(filters);
        details.appendChild(viewer);

        return details;
    }

    private handleDownloadLogs(): void {
        const text = getClientLogBuffer().toText();
        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `motivation-client-logs-${new Date().toISOString()}.txt`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 1000);
    }

    // ── Connectivity ────────────────────────────────────────────────────────

    private buildConnectivityPanel(): HTMLElement {
        const details = makePanel('Connectivity', true);

        const statusEl = makeCodeBlock();
        details.appendChild(statusEl);

        const pingResultEl = makeCodeBlock();
        pingResultEl.textContent = 'No ping yet.';
        details.appendChild(pingResultEl);

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        const pingBtn = makeButton('Ping backend', async () => {
            pingResultEl.textContent = `Pinging ${pingUrl()}…`;
            const result = await pingBackend(pingUrl());
            pingResultEl.textContent = formatPingResult(pingUrl(), result);
        }, 'connectivity-ping');
        toolbar.appendChild(pingBtn);
        details.appendChild(toolbar);

        const render = () => {
            const snap = snapshotConnectivity();
            statusEl.textContent = JSON.stringify(snap, null, 2);
        };
        render();
        this.connectivityTimer = setInterval(render, 2000);

        return details;
    }

    // ── Service Worker ──────────────────────────────────────────────────────

    private buildSwPanel(): HTMLElement {
        const details = makePanel('Service Worker', true);

        const statusEl = makeCodeBlock();
        statusEl.textContent = 'Loading…';
        details.appendChild(statusEl);

        const outputEl = makeCodeBlock();
        outputEl.textContent = '';
        details.appendChild(outputEl);

        const renderStatus = async () => {
            const result = await getSwStatus();
            statusEl.textContent = JSON.stringify(result, null, 2);
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh status', renderStatus, 'sw-refresh'),
            makeButton('Update', async () => {
                outputEl.textContent = JSON.stringify(await updateSw(), null, 2);
                await renderStatus();
            }, 'sw-update'),
            makeButton('Skip waiting', async () => {
                outputEl.textContent = JSON.stringify(await skipWaiting(), null, 2);
                await renderStatus();
            }, 'sw-skip-waiting'),
            makeButton('Unregister', async () => {
                if (!confirm('Unregister the service worker?')) return;
                outputEl.textContent = JSON.stringify(await unregisterSw(), null, 2);
                await renderStatus();
            }, 'sw-unregister'),
        );
        details.appendChild(toolbar);

        void renderStatus();
        return details;
    }

    // ── Storage ─────────────────────────────────────────────────────────────

    private buildStoragePanel(): HTMLElement {
        const details = makePanel('Storage', true);

        const cachesEl = makeCodeBlock();
        cachesEl.textContent = 'Loading caches…';
        details.appendChild(cachesEl);

        const dbsEl = makeCodeBlock();
        dbsEl.textContent = 'Loading IndexedDB…';
        details.appendChild(dbsEl);

        const outputEl = makeCodeBlock();
        outputEl.textContent = '';
        details.appendChild(outputEl);

        const refresh = async () => {
            cachesEl.textContent = JSON.stringify(await listCaches(), null, 2);
            dbsEl.textContent = JSON.stringify(await listDatabases(), null, 2);
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh', refresh, 'storage-refresh'),
            makeButton('Clear caches', async () => {
                if (!confirm('Delete all Cache Storage entries?')) return;
                outputEl.textContent = JSON.stringify(await clearAllCaches(), null, 2);
                await refresh();
            }, 'storage-clear-caches'),
            makeButton('Delete IDB', async () => {
                if (!confirm('Delete all IndexedDB databases?')) return;
                outputEl.textContent = JSON.stringify(await deleteAllDatabases(), null, 2);
                await refresh();
            }, 'storage-delete-idb'),
            makeButton('Nuke & reload', async () => {
                if (!confirm('Unregister SW, clear all caches and IDB, then reload?')) return;
                await nukeAndReload();
            }, 'storage-nuke'),
        );
        details.appendChild(toolbar);

        void refresh();
        return details;
    }
}

function pingUrl(): string {
    return `${API_URL}/health`;
}

function formatPingResult(url: string, r: PingResult): string {
    return JSON.stringify({ url, ...r }, null, 2);
}

function makePanel(title: string, open: boolean): HTMLDetailsElement {
    const details = document.createElement('details');
    details.className = 'debug-panel';
    details.open = open;
    const summary = document.createElement('summary');
    summary.textContent = title;
    details.appendChild(summary);
    return details;
}

function makeButton(label: string, onClick: () => void | Promise<void>, testId?: string): HTMLButtonElement {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'debug-btn';
    btn.textContent = label;
    if (testId) btn.dataset.testid = testId;
    btn.addEventListener('click', () => { void onClick(); });
    return btn;
}

function makeCodeBlock(): HTMLPreElement {
    const pre = document.createElement('pre');
    pre.className = 'debug-code';
    return pre;
}

if (!customElements.get('debug-screen')) {
    customElements.define('debug-screen', DebugScreen);
}
